const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const DataLoader = require('dataloader');

const typeDefs = `#graphql
  scalar DateTime

  type Query {
    users(limit: Int, offset: Int): [User!]!
    user(id: ID!): User
    posts(limit: Int, offset: Int, userId: ID): [Post!]!
    post(id: ID!): Post
    comments(limit: Int, offset: Int, postId: ID, userId: ID): [Comment!]!
    comment(id: ID!): Comment
  }

  type User {
    id: ID!
    name: String!
    createdAt: DateTime!
    posts(limit: Int, offset: Int): [Post!]!
  }

  type Post {
    id: ID!
    userId: ID!
    title: String!
    body: String!
    createdAt: DateTime!
    user: User!
    comments(limit: Int, offset: Int): [Comment!]!
  }

  type Comment {
    id: ID!
    postId: ID!
    userId: ID!
    body: String!
    createdAt: DateTime!
    user: User!
    post: Post!
  }
`;

function nowISO() {
  return new Date().toISOString();
}

function makeDB() {
  const users = [
    { id: 'u1', name: 'Ada', createdAt: nowISO() },
    { id: 'u2', name: 'Linus', createdAt: nowISO() },
    { id: 'u3', name: 'Grace', createdAt: nowISO() },
  ];

  const posts = [
    { id: 'p1', userId: 'u1', title: 'Hello World', body: 'First post', createdAt: nowISO() },
    { id: 'p2', userId: 'u1', title: 'GraphQL', body: 'Nested queries', createdAt: nowISO() },
    { id: 'p3', userId: 'u2', title: 'Node.js', body: 'Event loop', createdAt: nowISO() },
    { id: 'p4', userId: 'u3', title: 'Compilers', body: 'Parsing', createdAt: nowISO() },
  ];

  const comments = [
    { id: 'c1', postId: 'p1', userId: 'u2', body: 'Nice!', createdAt: nowISO() },
    { id: 'c2', postId: 'p1', userId: 'u3', body: 'Welcome', createdAt: nowISO() },
    { id: 'c3', postId: 'p2', userId: 'u3', body: 'Love GraphQL', createdAt: nowISO() },
    { id: 'c4', postId: 'p3', userId: 'u1', body: 'Great read', createdAt: nowISO() },
    { id: 'c5', postId: 'p3', userId: 'u3', body: 'Indeed', createdAt: nowISO() },
    { id: 'c6', postId: 'p4', userId: 'u2', body: 'Cool topic', createdAt: nowISO() },
  ];

  const userById = new Map(users.map(u => [u.id, u]));
  const postById = new Map(posts.map(p => [p.id, p]));
  const commentById = new Map(comments.map(c => [c.id, c]));

  return {
    users,
    posts,
    comments,
    userById,
    postById,
    commentById,
    findUsers({ limit, offset } = {}) {
      const o = offset ?? 0;
      const l = limit ?? users.length;
      return users.slice(o, o + l);
    },
    findPosts({ limit, offset, userId } = {}) {
      let list = posts;
      if (userId) list = list.filter(p => p.userId === userId);
      const o = offset ?? 0;
      const l = limit ?? list.length;
      return list.slice(o, o + l);
    },
    findComments({ limit, offset, postId, userId } = {}) {
      let list = comments;
      if (postId) list = list.filter(c => c.postId === postId);
      if (userId) list = list.filter(c => c.userId === userId);
      const o = offset ?? 0;
      const l = limit ?? list.length;
      return list.slice(o, o + l);
    },
    getUser(id) {
      return userById.get(id) || null;
    },
    getPost(id) {
      return postById.get(id) || null;
    },
    getComment(id) {
      return commentById.get(id) || null;
    },
  };
}

function createLoaders(db) {
  const userById = new DataLoader(async (ids) => {
    return ids.map(id => db.getUser(id));
  }, { cache: true });

  const postById = new DataLoader(async (ids) => {
    return ids.map(id => db.getPost(id));
  }, { cache: true });

  const commentById = new DataLoader(async (ids) => {
    return ids.map(id => db.getComment(id));
  }, { cache: true });

  const postsByUserId = new DataLoader(async (userIds) => {
    const grouped = new Map(userIds.map(id => [id, []]));
    for (const p of db.posts) {
      if (grouped.has(p.userId)) grouped.get(p.userId).push(p);
    }
    return userIds.map(id => grouped.get(id) || []);
  }, { cache: true });

  const commentsByPostId = new DataLoader(async (postIds) => {
    const grouped = new Map(postIds.map(id => [id, []]));
    for (const c of db.comments) {
      if (grouped.has(c.postId)) grouped.get(c.postId).push(c);
    }
    return postIds.map(id => grouped.get(id) || []);
  }, { cache: true });

  return {
    userById,
    postById,
    commentById,
    postsByUserId,
    commentsByPostId,
  };
}

const resolvers = {
  DateTime: {
    serialize(value) {
      if (value instanceof Date) return value.toISOString();
      if (typeof value === 'string') return value;
      return new Date(value).toISOString();
    },
    parseValue(value) {
      return new Date(value);
    },
    parseLiteral(ast) {
      if (!ast || !ast.value) return null;
      return new Date(ast.value);
    }
  },

  Query: {
    users: (_, args, ctx) => ctx.db.findUsers(args),
    user: (_, { id }, ctx) => ctx.loaders.userById.load(id),
    posts: (_, args, ctx) => ctx.db.findPosts(args),
    post: (_, { id }, ctx) => ctx.loaders.postById.load(id),
    comments: (_, args, ctx) => ctx.db.findComments(args),
    comment: (_, { id }, ctx) => ctx.loaders.commentById.load(id),
  },

  User: {
    posts: async (user, { limit, offset }, ctx) => {
      const all = await ctx.loaders.postsByUserId.load(user.id);
      const o = offset ?? 0;
      const l = limit ?? all.length;
      return all.slice(o, o + l);
    },
  },

  Post: {
    user: (post, _, ctx) => ctx.loaders.userById.load(post.userId),
    comments: async (post, { limit, offset }, ctx) => {
      const all = await ctx.loaders.commentsByPostId.load(post.id);
      const o = offset ?? 0;
      const l = limit ?? all.length;
      return all.slice(o, o + l);
    },
  },

  Comment: {
    user: (comment, _, ctx) => ctx.loaders.userById.load(comment.userId),
    post: (comment, _, ctx) => ctx.loaders.postById.load(comment.postId),
  },
};

async function main() {
  const db = makeDB();

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    introspection: true,
  });

  const { url } = await startStandaloneServer(server, {
    listen: { port: process.env.PORT ? Number(process.env.PORT) : 4000 },
    context: async () => {
      return {
        db,
        loaders: createLoaders(db),
      };
    },
  });

  console.log(`GraphQL API ready at ${url}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});